properties.valueHandler:
const selectedComponent = Utils.first(Vars.selectedComponents);
if (selectedComponent?.input?.size?.type == 'value') {
  return selectedComponent.input?.size?.value ?? 'medium';
}
return 'medium';

properties.stateHandler:
const selectedComponent = Utils.first(Vars.selectedComponents);
let state = 'enabled';
if (selectedComponent?.input?.size?.type == 'handler' && selectedComponent?.input?.size?.value) {
  state = 'disabled';
}
return state;

eventHandlers.valueChange:
const selectedComponent = Utils.first(Vars.selectedComponents);
const newSize = EventData.value;
updateInput(selectedComponent, 'size', 'string', newSize);

